class FoodForm{constructor(form){this.formName=form.attr("name");this.errors=$("#form_errors_client");this.options=$("#"+this.formName+"_foodstuffs option");$("#add_foodstuff").on("click",this.addFoodstuff.bind(this));$("#add_recipe").on("click",this.addRecipe.bind(this));form.on("input",".foodstuff-name",this.foodNameInput.bind(this,"foodstuff"));form.on("input",".recipe-name",this.foodNameInput.bind(this,"recipe"));form.on("click",".foodstuff-result",this.foodSearchResultClick.bind(this,"foodstuff"));form.on("click",".recipe-result",this.foodSearchResultClick.bind(this,"recipe"));form.on("click",".remove-row",this.removeRow.bind(this));form.on("submit",this.submit.bind(this))}addFoodstuff(event){let html="<tr><td>"+$("#"+this.formName+"_foodstuff_dropdown").data("prototype")+"</td>";html+="<td>"+$("#"+this.formName+"_foodstuff_weights").data("prototype")+"</td>";html+="<td>"+$("#"+this.formName+"_foodstuff_units").data("prototype")+"</td>";html+='<td><i class="remove-row fa fa-minus"></i></td></tr>';html=this.removeLabels(html);$("#add_foodstuff_recipe_button_row").before(html);$("#"+this.formName+"_foodstuff_weights___name__").removeAttr("id");event.preventDefault()}addRecipe(event){let html="<tr><td>"+$("#"+this.formName+"_recipe_dropdown").data("prototype")+"</td>";html+='<td colspan="2">'+$("#"+this.formName+"_recipe_weights").data("prototype")+"</td>";html+='<td><i class="remove-row fa fa-minus"></i></td></tr>';html=this.removeLabels(html);$("#add_foodstuff_recipe_button_row").before(html);let options=$("#"+this.formName+"_recipe_weights___name__");options.val(1);options.removeAttr("id");event.preventDefault()}removeLabels(html){return html.replaceAll(/<label[\s\S]+?<\/label>/g,"")}foodNameInput(foodType,event){let thisElement=$(event.target);let row=new this.FoodRow(event.target);let valueInput=encodeURI(thisElement.val().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,""));let searchResults=row.getSearchResults();searchResults.html("");let url;if(foodType==="foodstuff"){url=$("#foodstuff_search").data("search").replace("__name__",valueInput)}else{url=$("#recipe_search").data("search").replace("__title__",valueInput)}if(this.timeout){clearTimeout(this.timeout);this.timeout=null}this.timeout=setTimeout(()=>{$.ajax({url:url,type:"GET",success:data=>{if(valueInput!==""){searchResults.html(data)}else{searchResults.html("")}$("."+foodType+"-result").each((index,element)=>{let id=$(element).attr("id").replace(foodType+"_result_","");let name=$(element).text().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"");if(valueInput===name){row.getWeight().attr("name",this.formName+"["+foodType+"_weights]["+id+"]");row.getUnit().attr("name",this.formName+"["+foodType+"_units]["+id+"]")}})},error:()=>{searchResults.html("Er ging iets fout.")}})},1e3)}foodSearchResultClick(foodType,event){let thisElement=$(event.target);let row=new this.FoodRow(event.target);let id=thisElement.attr("id").replace(foodType+"_result_","");let name=thisElement.text();row.getName().val(name);row.getWeight().attr("name",this.formName+"["+foodType+"_weights]["+id+"]");row.getUnit().attr("name",this.formName+"["+foodType+"_units]["+id+"]")}removeRow(event){new this.FoodRow(event.target).row.remove()}submit(event){let text="";let foodstuffNames=[];$(".foodstuff-name").each((index,element)=>{if(foodstuffNames.includes($(element).val())){text=text+"Dubbel voedingsmiddel. <br>";event.preventDefault()}foodstuffNames.push($(element).val())});let recipeNames=[];$(".recipe-name").each((index,element)=>{if(recipeNames.includes($(element).val())){text=text+"Dubbel recept.";event.preventDefault()}recipeNames.push($(element).val())});if(this.formName==="foodstuff_from_foodstuffs"){let sum=0;$(".food-weight").each((index,element)=>{sum=sum+parseFloat($(element).val().replace(",","."))});if(Math.round(sum*100)!==1e4){text=text+"De gewichten zijn samen niet gelijk aan 100 procent. <br>";event.preventDefault()}}this.errors.html(text)}FoodRow=class{constructor(thisElement){this.row=$(thisElement).closest("tr")}getName(){return this.row.find(".dropdown-toggle")}getWeight(){return this.row.find(".food-weight")}getUnit(){return this.row.find(".food-unit")}getSearchResults(){return this.row.find(".dropdown-menu-food")}}}